     static openHelpCenter(tranHisMsg) { 
         const { transCategory } = tranHisMsg || {}; 
         if (!transCategory) { 
             return; 
         } 
         const categoryMap = TransactionHelperNew.transCategoriesMap?.[transCategory]; 

         const transCategoryLevels = 
             categoryMap?.parentArray || tranHisMsg.transCategoryLevels || []; 

         const transaction = { ...tranHisMsg, transCategoryLevels }; 

         TranHisHelper.getDeviceInfo().then(deviceInfo => { 
             const isSupportStartFeedback = deviceInfo?.buildVersion >= 41032; 
             if (isSupportStartFeedback) { 
                 MaxApi.startToFeedback({ transaction, forService: 'lsgd' }); 
                 return; 
             } 
             MaxApi.startFeatureCode('helpcenter_transaction_new', { transaction }); 
         }); 
     }
